import{_ as t,c as s,o as a,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Sisyphus: Multi-Agent Coordination | oh-my-opencode","description":"Master multi-agent coordination and task delegation. Learn to coordinate multiple AI agents efficiently with Sisyphus orchestrator best practices.","frontmatter":{"title":"Sisyphus: Multi-Agent Coordination | oh-my-opencode","sidebarTitle":"Sisyphus","subtitle":"Main Orchestrator: Think and Execute Like a Senior Engineer","description":"Master multi-agent coordination and task delegation. Learn to coordinate multiple AI agents efficiently with Sisyphus orchestrator best practices.","tags":["orchestration","sisyphus","agent"],"prerequisite":["start-installation"],"order":20},"headers":[],"relativePath":"code-yeongyu/oh-my-opencode/start/sisyphus-orchestrator/index.md","filePath":"code-yeongyu/oh-my-opencode/start/sisyphus-orchestrator/index.md"}'),n={name:"code-yeongyu/oh-my-opencode/start/sisyphus-orchestrator/index.md"};function o(r,e,l,p,d,h){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="main-orchestrator-think-and-execute-like-a-senior-engineer" tabindex="-1">Main Orchestrator: Think and Execute Like a Senior Engineer <a class="header-anchor" href="#main-orchestrator-think-and-execute-like-a-senior-engineer" aria-label="Permalink to &quot;Main Orchestrator: Think and Execute Like a Senior Engineer&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Understand how Sisyphus coordinates work like a real development team</li><li>Master best practices for task delegation, enabling different expert agents to collaboratively complete complex tasks</li><li>Learn how to significantly improve development efficiency through parallel background tasks</li><li>Know when to let agents handle tasks themselves and when to delegate to experts</li></ul><h2 id="your-current-struggles" tabindex="-1">Your Current Struggles <a class="header-anchor" href="#your-current-struggles" aria-label="Permalink to &quot;Your Current Struggles&quot;">​</a></h2><p>You may have encountered these problems:</p><ul><li>AI agents &quot;give up halfway&quot; and forget their goals while writing</li><li>The same file gets modified repeatedly, requiring re-reading context each time</li><li>You want AI to handle many tasks but can only queue them one by one</li><li>Agents write code, but you still have to verify whether it&#39;s correct and if it breaks other features</li></ul><p><strong>Root Cause</strong>: You&#39;re asking a &quot;jack-of-all-trades&quot; to do all the work, but only experts truly understand specialized tasks.</p><h2 id="when-to-use-this" tabindex="-1">When to Use This <a class="header-anchor" href="#when-to-use-this" aria-label="Permalink to &quot;When to Use This&quot;">​</a></h2><p>Sisyphus is your main orchestrator, suitable for these scenarios:</p><table tabindex="0"><thead><tr><th>Scenario</th><th>Suitable</th><th>Alternative</th></tr></thead><tbody><tr><td>Complex feature development (3+ steps)</td><td>✅ Highly Recommended</td><td>Prometheus + Atlas (requires detailed planning)</td></tr><tr><td>Quick fix of known bugs</td><td>✅ Appropriate</td><td>Let Sisyphus handle it directly</td></tr><tr><td>Need to research multiple repos/docs</td><td>✅ Highly Recommended</td><td>Use Sisyphus parallel delegation</td></tr><tr><td>Simple single-file modifications</td><td>✅ Acceptable</td><td>Direct editing (simpler)</td></tr><tr><td>Need detailed project planning</td><td>⚠️ Not Recommended</td><td>Use Prometheus to generate plan first</td></tr></tbody></table><h2 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h2><p><strong>Sisyphus</strong> is the main orchestrator agent that coordinates multiple AI experts like a real development team. Through responsibility separation and parallel delegation mechanisms, it enables professional sub-agents to leverage their respective strengths, achieving efficient collaboration.</p><p>Sisyphus is not a &quot;smarter AI&quot;—it&#39;s an <strong>orchestration system</strong>.</p><h3 id="responsibility-separation" tabindex="-1">Responsibility Separation <a class="header-anchor" href="#responsibility-separation" aria-label="Permalink to &quot;Responsibility Separation&quot;">​</a></h3><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    User[👤 You] --&gt; Sisyphus[⚡ Sisyphus&lt;br/&gt;Main Orchestrator]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Sisyphus --&gt; Explore[🔍 Explore&lt;br/&gt;Codebase Search]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Sisyphus --&gt; Librarian[📚 Librarian&lt;br/&gt;Documentation Research]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Sisyphus --&gt; Oracle[🧠 Oracle&lt;br/&gt;Architecture Consultation]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Sisyphus --&gt; Junior[🪨 Sisyphus-Junior&lt;br/&gt;Task Execution]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Explore -.Parallel.-&gt; Sisyphus</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Librarian -.Parallel.-&gt; Sisyphus</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Oracle -.-&gt; Sisyphus</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Junior -.-&gt; Sisyphus</span></span></code></pre></div><p><strong>Sisyphus doesn&#39;t write code</strong>. It&#39;s responsible for:</p><ol><li><strong>Understanding your real needs</strong> (not just surface-level requests)</li><li><strong>Determining who&#39;s best suited for the task</strong> (not doing everything itself)</li><li><strong>Delegating tasks in parallel</strong> (letting multiple experts work simultaneously)</li><li><strong>Verifying results</strong> (never blindly trusting &quot;I&#39;m done&quot;)</li></ol><h3 id="why-the-name-sisyphus" tabindex="-1">Why the Name Sisyphus? <a class="header-anchor" href="#why-the-name-sisyphus" aria-label="Permalink to &quot;Why the Name Sisyphus?&quot;">​</a></h3><p>In Greek mythology, Sisyphus was punished to endlessly push a boulder up a mountain.</p><p>This system&#39;s design philosophy: <strong>Agents must complete all TODOs (finish pushing the boulder) before they can stop</strong>.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>This isn&#39;t punishment—it&#39;s a quality assurance mechanism. You don&#39;t want AI to give up halfway and leave a mess behind.</p></div><h3 id="_32k-thinking-budget" tabindex="-1">32k Thinking Budget <a class="header-anchor" href="#_32k-thinking-budget" aria-label="Permalink to &quot;32k Thinking Budget&quot;">​</a></h3><p>Sisyphus uses <strong>Claude Opus 4.5 + 32k thinking budget</strong>.</p><p>What&#39;s the benefit?</p><table tabindex="0"><thead><tr><th>Low Budget (No Thinking)</th><th>32k Thinking Budget</th></tr></thead><tbody><tr><td>Starts writing code directly</td><td>First deeply analyzes requirements, assesses complexity, breaks down tasks</td></tr><tr><td>Prone to missing edge cases</td><td>Proactively identifies potential issues and risks</td></tr><tr><td>Realizes it&#39;s on the wrong track halfway</td><td>Chooses the optimal approach from the start</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Strongly recommend configuring <strong>Opus 4.5</strong> model for Sisyphus. The experience will be significantly worse with other models.</p></div><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-create-a-test-project" tabindex="-1">Step 1: Create a Test Project <a class="header-anchor" href="#step-1-create-a-test-project" aria-label="Permalink to &quot;Step 1: Create a Test Project&quot;">​</a></h3><p><strong>Why</strong> You need a runnable project to observe Sisyphus&#39;s behavior.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-app</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> next-app@latest</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --typescript</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tailwind</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --eslint</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-src-dir</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><p><strong>You should see</strong>: Project initialization complete, you can run <code>npm run dev</code> to start.</p><h3 id="step-2-give-sisyphus-a-complex-task" tabindex="-1">Step 2: Give Sisyphus a Complex Task <a class="header-anchor" href="#step-2-give-sisyphus-a-complex-task" aria-label="Permalink to &quot;Step 2: Give Sisyphus a Complex Task&quot;">​</a></h3><p>Open the project in OpenCode and enter:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Add user login functionality, including:</span></span>
<span class="line"><span>- Email/password login</span></span>
<span class="line"><span>- JWT token storage</span></span>
<span class="line"><span>- Protected routes</span></span>
<span class="line"><span>- Login status check</span></span></code></pre></div><p>Observe Sisyphus&#39;s response.</p><p><strong>You should see</strong>:</p><ol><li>Sisyphus doesn&#39;t immediately start writing code</li><li>It first creates a TODO list (detailed task breakdown)</li><li>Evaluates codebase patterns (checks configuration, file structure)</li><li>May ask you a few clarifying questions</li></ol><p><strong>Checkpoint ✅</strong>: Check OpenCode&#39;s TODO panel, you should see something like:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>□ Install necessary dependencies (bcrypt, jsonwebtoken)</span></span>
<span class="line"><span>□ Create user model and type definitions</span></span>
<span class="line"><span>□ Implement login API endpoint</span></span>
<span class="line"><span>□ Create JWT signing and verification utilities</span></span>
<span class="line"><span>□ Add protected route middleware</span></span>
<span class="line"><span>□ Implement frontend login form</span></span>
<span class="line"><span>□ Add login state management</span></span></code></pre></div><h3 id="step-3-observe-parallel-delegation-critical-moment" tabindex="-1">Step 3: Observe Parallel Delegation (Critical Moment) <a class="header-anchor" href="#step-3-observe-parallel-delegation-critical-moment" aria-label="Permalink to &quot;Step 3: Observe Parallel Delegation (Critical Moment)&quot;">​</a></h3><p>During implementation, Sisyphus may:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Background Task Started]</span></span>
<span class="line"><span>- Task ID: bg_abc123</span></span>
<span class="line"><span>- Agent: explore</span></span>
<span class="line"><span>- Prompt: &quot;Find existing auth patterns in this codebase...&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[Background Task Started]</span></span>
<span class="line"><span>- Task ID: bg_def456</span></span>
<span class="line"><span>- Agent: librarian</span></span>
<span class="line"><span>- Prompt: &quot;Research JWT best practices for Next.js...&quot;</span></span></code></pre></div><p><strong>This is key</strong>: Sisyphus <strong>doesn&#39;t wait</strong> for these tasks to complete—it continues working.</p><p>When you need results, it calls <code>background_output(task_id=&quot;...&quot;)</code> to retrieve them.</p><p><strong>Why is this faster?</strong></p><table tabindex="0"><thead><tr><th>Serial Approach (Traditional)</th><th>Parallel Approach (Sisyphus)</th></tr></thead><tbody><tr><td>Codebase search (2 min)</td><td>⏳ Codebase search (2 min)</td></tr><tr><td>Waiting...</td><td>⏳ Documentation research (2 min, concurrent)</td></tr><tr><td>Documentation research (2 min)</td><td>Start implementation (total 2 min)</td></tr><tr><td>Start implementation (2 min)</td><td></td></tr><tr><td><strong>Total: 6 min</strong></td><td><strong>Total: 4 min (33% saved)</strong></td></tr></tbody></table><h3 id="step-4-verification-mechanism" tabindex="-1">Step 4: Verification Mechanism <a class="header-anchor" href="#step-4-verification-mechanism" aria-label="Permalink to &quot;Step 4: Verification Mechanism&quot;">​</a></h3><p>When Sisyphus claims &quot;task complete&quot;, it will:</p><ol><li>Run <code>lsp_diagnostics</code> to check for errors</li><li>Run <code>npm run build</code> to ensure build passes</li><li>Run test suite if tests exist</li><li>Mark TODO as <code>completed</code></li></ol><p><strong>Checkpoint ✅</strong>: Check terminal output, you should see something like:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✓ Running diagnostics on changed files...</span></span>
<span class="line"><span>✓ No errors found</span></span>
<span class="line"><span>✓ Build passed (exit code 0)</span></span>
<span class="line"><span>✓ All tests passed</span></span></code></pre></div><p>If any verification fails, Sisyphus will immediately fix it—never leaving a mess behind.</p><h3 id="step-5-common-pitfalls" tabindex="-1">Step 5: Common Pitfalls <a class="header-anchor" href="#step-5-common-pitfalls" aria-label="Permalink to &quot;Step 5: Common Pitfalls&quot;">​</a></h3><h4 id="❌-wrong-practice-interrupt-sisyphus-s-todo-tracking" tabindex="-1">❌ Wrong Practice: Interrupt Sisyphus&#39;s TODO Tracking <a class="header-anchor" href="#❌-wrong-practice-interrupt-sisyphus-s-todo-tracking" aria-label="Permalink to &quot;❌ Wrong Practice: Interrupt Sisyphus&#39;s TODO Tracking&quot;">​</a></h4><p>You see Sisyphus working on tasks and you&#39;re impatient:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hurry up and write code! Stop planning!</span></span></code></pre></div><p><strong>Problem</strong>: Sisyphus will skip TODOs and write code directly, potentially missing edge cases.</p><p><strong>Correct Practice</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Wait for Sisyphus to finish planning. If you think the plan is wrong, give specific improvement suggestions:</span></span>
<span class="line"><span>&quot;Step 3 in the TODO should consider the database migration plan first.&quot;</span></span></code></pre></div><h4 id="❌-wrong-practice-not-letting-sisyphus-delegate" tabindex="-1">❌ Wrong Practice: Not Letting Sisyphus Delegate <a class="header-anchor" href="#❌-wrong-practice-not-letting-sisyphus-delegate" aria-label="Permalink to &quot;❌ Wrong Practice: Not Letting Sisyphus Delegate&quot;">​</a></h4><p>You disable all expert agents in configuration, leaving only Sisyphus.</p><p><strong>Problem</strong>: Sisyphus will try to do everything itself, but may not be professional enough.</p><p><strong>Correct Practice</strong>:</p><p>Keep default configuration and let Sisyphus automatically delegate to experts:</p><table tabindex="0"><thead><tr><th>Task</th><th>Sisyphus Itself</th><th>Delegate to Expert</th></tr></thead><tbody><tr><td>Simple single-file modification</td><td>✅ OK</td><td>Not needed</td></tr><tr><td>Codebase search</td><td>⚠️ Slow</td><td>✅ Explore (faster)</td></tr><tr><td>Documentation research</td><td>⚠️ May be inaccurate</td><td>✅ Librarian (more professional)</td></tr><tr><td>Architecture decisions</td><td>❌ Not recommended</td><td>✅ Oracle (more authoritative)</td></tr></tbody></table><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><p>Sisyphus&#39;s power doesn&#39;t come from being &quot;smarter&quot;, but from:</p><ol><li><strong>Responsibility Separation</strong>: Main orchestrator + professional team, not working alone</li><li><strong>Deep Thinking</strong>: 32k thinking budget ensures no details are missed</li><li><strong>Parallel Execution</strong>: Background tasks let multiple experts work simultaneously</li><li><strong>Mandatory Verification</strong>: No evidence = task not complete</li><li><strong>TODO Tracking</strong>: Giving up halfway is not allowed</li></ol><p><strong>Core Principles</strong>:</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><strong>Delegate by Default</strong>: Unless the task is extremely simple (single file, known location), prioritize delegating to experts or using Category+Skill.</p></div><h2 id="preview-next-lesson" tabindex="-1">Preview Next Lesson <a class="header-anchor" href="#preview-next-lesson" aria-label="Permalink to &quot;Preview Next Lesson&quot;">​</a></h2><blockquote><p>Next lesson, we&#39;ll learn <strong><a href="./../ultrawork-mode/">Ultrawork Mode</a></strong> to activate all features with one click, letting Sisyphus go all-out to complete complex tasks.</p><p>You&#39;ll learn:</p><ul><li>How to quickly start tasks using the <code>ultrawork</code> keyword</li><li>What additional capabilities Ultrawork mode activates</li><li>When to use Ultrawork vs. when to use Prometheus</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-26</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Lines</th></tr></thead><tbody><tr><td>Sisyphus agent factory</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/sisyphus.ts" target="_blank" rel="noreferrer"><code>src/agents/sisyphus.ts</code></a></td><td>419-450</td></tr><tr><td>Sisyphus core prompt</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/sisyphus.ts" target="_blank" rel="noreferrer"><code>src/agents/sisyphus.ts</code></a></td><td>17-416</td></tr><tr><td>Agent metadata and model configuration</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/AGENTS.md" target="_blank" rel="noreferrer"><code>src/agents/AGENTS.md</code></a></td><td>24-36</td></tr><tr><td>Tool permission restrictions</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/AGENTS.md" target="_blank" rel="noreferrer"><code>src/agents/AGENTS.md</code></a></td><td>44-51</td></tr></tbody></table><p><strong>Key Configuration</strong>:</p><ul><li><strong>Thinking Budget</strong>: 32k tokens (Anthropic models only)</li><li><strong>Temperature</strong>: 0.1 (code agents fixed low temperature)</li><li><strong>Max Tokens</strong>: 64000</li><li><strong>Recommended Model</strong>: anthropic/claude-opus-4-5</li></ul><p><strong>Core Workflow</strong> (from source code):</p><ul><li><strong>Phase 0</strong>: Intent Gate (intent classification, lines 53-103)</li><li><strong>Phase 1</strong>: Codebase Assessment (codebase evaluation, lines 107-130)</li><li><strong>Phase 2A</strong>: Exploration &amp; Research (lines 132-172)</li><li><strong>Phase 2B</strong>: Implementation (lines 176-263)</li><li><strong>Phase 2C</strong>: Failure Recovery (lines 266-283)</li><li><strong>Phase 3</strong>: Completion (lines 286-302)</li></ul><p><strong>Key Constraints</strong>:</p><ul><li><strong>Non-trivial tasks must create TODO</strong> (line 311)</li><li><strong>Background tasks must be parallel</strong> (lines 144-162)</li><li><strong>Must verify results</strong> (lines 254-262)</li></ul></details>`,75)])])}const g=t(n,[["render",o]]);export{u as __pageData,g as default};
